<script lang="ts">
  import type { PlaySession,ChatMessage } from '@simbot/session';
  import type { CardAsset } from '@simbot/card';
  import Icon from '@simbot/ui/Icon.svelte';
  import {prepareDisplayContent,renderDisplayContent} from './display-macros';
  import {explainAssetLookup} from '@simbot/risu';
  import {diagnostics} from './diagnostics.svelte.ts';
  import { toFactLine } from './FactReceipt.svelte';
  import { presentNarrativeIssues } from './narrative-issues';
  import {buildNpcClusters,extractAssetSpeakers} from './npc-gallery';
  import {tick} from 'svelte';

  let {session,version,scrollRequest=0,greetings=[],cardName,userName='나',userPortrait=null,botPortrait=null,model,waiting=false,assets=[],assetWidth=32,portraitFor,onassetneeded=()=>{},onchange,oncontinue,onerror=()=>{}}:{session:PlaySession;version:number;scrollRequest?:number;greetings?:string[];cardName:string;userName?:string;userPortrait?:string|null;botPortrait?:string|null;model:string;waiting?:boolean;assets?:CardAsset[];assetWidth?:number;portraitFor:(id:string,emotion?:string,outfit?:number)=>string|null;onassetneeded?:(name:string)=>void;onchange:()=>void;oncontinue?:()=>Promise<void>;onerror?:(message:string)=>void}=$props();
  let editing=$state<string|null>(null),draft=$state(''),rerolling=$state(false),translating=$state<string|null>(null),translationShown=$state<Record<string,boolean>>({}),detailsFor=$state<string|null>(null),greetingIndex=$state(0),lastSessionId=$state(''),live=$state(0),menuFor=$state<string|null>(null),issuesOpen=$state(false),bottom=$state<HTMLElement>(),pinned=true,previousCount=0,previousWaiting=false,previousRequest=0;
  $effect(()=>{void version;if(lastSessionId!==session.id){lastSessionId=session.id;greetingIndex=Math.max(0,greetings.indexOf(session.messages[0]?.content??''));issuesOpen=false;cancel();}});
  $effect(()=>session.subscribe(()=>{live+=1;}));
  let messages=$derived.by(()=>{void version;void live;return session.messages;}),narrativeWarning=$derived.by(()=>{void version;void live;const last=session.messages.at(-1);return last?.role==='assistant'?presentNarrativeIssues(last.content,session.narrativeIssues).warning:null;});
  function scrollHost(node:HTMLElement|undefined){let current=node?.parentElement??null;while(current){const style=getComputedStyle(current);if(/auto|scroll/.test(style.overflowY)&&current.scrollHeight>current.clientHeight+1)return current;current=current.parentElement;}return document.scrollingElement as HTMLElement|null;}
  function nearBottom(){const host=scrollHost(bottom);return!host||host.scrollHeight-host.scrollTop-host.clientHeight<160;}
  $effect.pre(()=>{void messages.length;void waiting;void scrollRequest;if(bottom)pinned=nearBottom();});
  $effect(()=>{const count=messages.length,isWaiting=waiting,request=scrollRequest,lastRole=messages.at(-1)?.role,requestChanged=request!==previousRequest,userAdded=count>previousCount&&lastRole==='user',contentChanged=count!==previousCount||isWaiting!==previousWaiting,shouldScroll=requestChanged||userAdded||(pinned&&contentChanged);previousCount=count;previousWaiting=isWaiting;previousRequest=request;if(shouldScroll)void tick().then(()=>bottom?.scrollIntoView({block:'end'}));});
  const guard=(work:()=>Promise<void>)=>work().catch(e=>onerror(e instanceof Error?e.message:String(e)));
  function name(message:ChatMessage){return message.role==='user'?userName:cardName;}
  export function displayMacros(content:string,user:string,char:string){return content.replace(/{{\s*user\s*}}/gi,user).replace(/{{\s*char\s*}}/gi,char);}
  function assetOptions(){const value=session.runtime.state.npcs,outfits:Record<string,number>={};if(value&&typeof value==='object'&&!Array.isArray(value))for(const[id,npc]of Object.entries(value as Record<string,unknown>)){const outfit=npc&&typeof npc==='object'&&!Array.isArray(npc)?Number((npc as Record<string,unknown>).outfit):Number.NaN;if(Number.isInteger(outfit))outfits[id]=outfit;}const declared=session.runtime.project.content.activeModules;return{outfits,activeModules:[...(session.runtime.project.moduleIds??[]),...(Array.isArray(declared)?declared.map(String):[])]};}
  // 렌더는 상태를 바꾸지 않는다(M-S0). 진단 기록도 마찬가지 — diagnostics는 평범한 배열에 담고
  // UI 알림은 마이크로태스크로 미룬다. 같은 사건은 재렌더로 쌓이지 않는다(수집기가 중복을 지운다).
  function report(message:ChatMessage,warning:{code:string;macro:string;name:string}){
    const where={card:cardName,chat:session.id,message:message.index};
    if(warning.code==='asset_missing'){const found=explainAssetLookup(warning.name,assets,assetOptions());
      diagnostics.record({...where,kind:'asset',code:'asset_missing',summary:`에셋 해석 실패: ${warning.name}`,detail:{'명령':`{{${warning.macro}::${warning.name}}}`,'시도한 이름':found.tried.join(', '),'변형 그룹':found.variantGroup,'있는 변형':found.variantsAvailable.length?found.variantsAvailable.join(', '):'(없음)','엔진 의상':found.outfitOwner?`${found.outfitOwner} = ${found.outfit}`:'(미지정)','결과':'asset_missing'}});
      return;}
    if(warning.code==='cbs_budget_exceeded'){diagnostics.record({...where,kind:'cbs',code:'cbs_budget_exceeded',summary:`CBS 예산 초과: ${warning.macro}`,detail:{'상한 종류':warning.macro,'실제 > 상한':warning.name,'결과':'파싱을 접고 원문을 표시함'}});return;}
    diagnostics.record({...where,kind:'asset',code:warning.code,summary:`${warning.macro} 처리 실패: ${warning.name}`,detail:{'명령':warning.macro,'이름':warning.name}});
  }
  function rendered(message:ChatMessage){const result=renderDisplayContent(message.content,userName,cardName,assets,session.regexScripts,session.cbsVariables,message.index,session.messages.length-1,assetOptions());for(const warning of result.warnings){report(message,warning);if(warning.code==='asset_missing')onassetneeded(warning.name);}return result.html;}
  function cancel(){editing=null;draft='';}
  async function save(message:ChatMessage){if(draft.trim()&&draft!==message.content)await session.editMessage(message.id,draft);cancel();onchange();}
  async function toggleEdit(message:ChatMessage){if(editing===message.id){await save(message);return;}editing=message.id;draft=message.content;}
  function handleEditKey(event:KeyboardEvent,message:ChatMessage){if(event.key==='Escape'){event.preventDefault();cancel();}else if(event.key==='Enter'&&(event.ctrlKey||event.metaKey)){event.preventDefault();void guard(()=>save(message));}}
  async function remove(message:ChatMessage,cascade=false){menuFor=null;if(!confirm(cascade?'이 메시지 이후를 전부 삭제할까요?':'이 메시지를 삭제할까요?'))return;await session.removeMessage(message.id,cascade);onchange();}
  async function previous(message:ChatMessage){const current=session.responseAlternateIndex(message.id);if(current<=0)return;rerolling=true;try{await session.showResponseAlternate(message.id,current-1);onchange();}finally{rerolling=false;}}
  async function next(message:ChatMessage){rerolling=true;try{const current=session.responseAlternateIndex(message.id),last=session.responseAlternateCount(message.id);if(current<last)await session.showResponseAlternate(message.id,current+1);else await session.rerollResponse(message.id);onchange();}finally{rerolling=false;}}
  async function reroll(message:ChatMessage){rerolling=true;try{await session.rerollResponse(message.id);issuesOpen=false;onchange();}finally{rerolling=false;}}
  async function greeting(delta:number){greetingIndex=(greetingIndex+delta+greetings.length)%greetings.length;await session.replaceGreeting(greetings[greetingIndex]!);onchange();}
  function runFor(message:ChatMessage){return session.promptRuns.find(run=>run.id.endsWith(`:${message.id}`));}
  async function translate(message:ChatMessage){if(translationShown[message.id]){translationShown[message.id]=false;return;}translating=message.id;try{await session.translateMessage(message.id,'한국어');translationShown[message.id]=true;onchange();}finally{translating=null;}}
  function tokenLabel(message:ChatMessage){const run=runFor(message);if(!run)return'';return `${run.tokensEstimated?'≈':''}${(run.inputTokens??0)+(run.outputTokens??0)} tok`;}
  function factsFor(message:ChatMessage,index:number){return(message.facts??(index===messages.length-1?session.lastLogs:[])).map(toFactLine);}
  function speakersFor(message:ChatMessage){return session.resolveSpeakers(message.speakers??[]);}
  let spriteGroups=$derived(buildNpcClusters(assets));
  const speakerKey=(value:string)=>value.normalize('NFKC').toLowerCase().replace(/[^a-z0-9가-힣]+/g,'');
  function stageSpeakersFor(message:ChatMessage){if(message.role!=='assistant')return[];const options=assetOptions(),prepared=prepareDisplayContent(message.content,userName,cardName,session.regexScripts,session.cbsVariables,message.index,session.messages.length-1,options.activeModules),inline=new Set(extractAssetSpeakers(prepared,spriteGroups).map(item=>speakerKey(item.npcId)));return speakersFor(message).filter(item=>!inline.has(speakerKey(item.npcId))&&!!portraitFor(item.npcId,item.emotion,item.outfit));}
  function avatarFor(message:ChatMessage){return message.role==='user'?userPortrait:botPortrait;}
</script>

<div class="list">
  {#each messages as message,index(message.id)}
    <article class="message" class:user={message.role==='user'}>
      <div class="avatar" class:empty={!avatarFor(message)}>{#if avatarFor(message)}<img src={avatarFor(message)!} alt=""/>{/if}</div>
      <div class="body">
        <div class="head"><strong>{name(message)}</strong><div class="tools">{#if message.role==='assistant'}<button class="tool-label" class:active={translationShown[message.id]} title="번역" disabled={translating===message.id} onclick={()=>void guard(()=>translate(message))}>{translating===message.id?'번역 중':'번역'}</button>{#if messages.length===1&&greetings.length>1}<span class="swipe"><button title="이전 첫 메시지" onclick={()=>void guard(()=>greeting(-1))}><Icon name="left"/></button><b>{greetingIndex+1}/{greetings.length}</b><button title="다음 첫 메시지" onclick={()=>void guard(()=>greeting(1))}><Icon name="right"/></button></span>{:else if message.origin==='model'&&session.canRerollResponse(message.id)}<span class="swipe"><button title="이전 응답" disabled={rerolling||session.responseAlternateIndex(message.id)===0} onclick={()=>void guard(()=>previous(message))}><Icon name="left"/></button><b>{session.responseAlternateIndex(message.id)+1}/{session.responseAlternateCount(message.id)+1}</b><button title="다음 응답" disabled={rerolling} onclick={()=>void guard(()=>next(message))}><Icon name="right"/></button></span><button title="이 응답부터 다시 생성" disabled={rerolling} onclick={()=>void guard(()=>reroll(message))}><Icon name="refresh"/></button>{/if}{#if index===messages.length-1&&message.origin==='model'&&oncontinue}<button class="tool-label" title="계속 생성" disabled={waiting} onclick={()=>void oncontinue?.()}>계속</button>{/if}{/if}<button title="응답 메뉴" onclick={()=>menuFor=menuFor===message.id?null:message.id}><Icon name="ellipsis"/></button>{#if menuFor===message.id}<div class="menu"><button onclick={()=>void guard(()=>toggleEdit(message))}><Icon name="pencil" size={14}/>{editing===message.id?'편집 저장':'편집'}</button><button onclick={()=>navigator.clipboard.writeText(message.content)}><Icon name="copy" size={14}/>복사</button>{#if runFor(message)}<button onclick={()=>{detailsFor=detailsFor===message.id?null:message.id;menuFor=null;}}><Icon name="bot" size={14}/>응답 정보</button>{/if}<button onclick={()=>void guard(()=>remove(message))}><Icon name="trash" size={14}/>삭제</button><button onclick={()=>void guard(()=>remove(message,true))}><Icon name="trash" size={14}/>이 메시지 이후 전부 삭제</button></div>{/if}</div></div>
        {#if editing===message.id}
          <div class="editor"><textarea bind:value={draft} onkeydown={(event)=>handleEditKey(event,message)}></textarea><div><button onclick={()=>void guard(()=>save(message))}>저장</button><button onclick={cancel}>취소</button></div></div>
        {:else}{@const stageSpeakers=stageSpeakersFor(message)}{#if stageSpeakers.length}<div class="response-sprites" class:multiple={stageSpeakers.length>1} style={`--asset-width:${assetWidth}rem`} role="group" aria-label="이 응답의 감정 스프라이트">{#each stageSpeakers as speaker}{@const portrait=portraitFor(speaker.npcId,speaker.emotion,speaker.outfit)}{#if portrait}<figure title={`${speaker.name} · ${speaker.emotion??'default'}`}><img src={portrait} alt={`${speaker.name} · ${speaker.emotion??'default'}`}/></figure>{/if}{/each}</div>{/if}<div class="text" style={`--asset-width:${assetWidth}rem`}>{@html rendered(message)}</div>{#if translationShown[message.id]&&message.translation}<div class="translation"><small>번역</small><div class="text" style={`--asset-width:${assetWidth}rem`}>{@html renderDisplayContent(message.translation,userName,cardName,assets,session.regexScripts,session.cbsVariables,message.index,session.messages.length-1,assetOptions()).html}</div></div>{/if}{/if}
        {#if message.role==='assistant'}<div class="meta">{#if message.origin==='model'}<span class="model"><Icon name="bot" size={13}/>{model}</span>{/if}{#if tokenLabel(message)}<span class="tokens">{tokenLabel(message)}</span>{/if}</div>{#if detailsFor===message.id&&runFor(message)}{@const run=runFor(message)!}<section class="run-detail"><header><strong>응답 정보</strong><button onclick={()=>detailsFor=null}>닫기</button></header><dl><div><dt>프로바이더</dt><dd>{run.provider??'알 수 없음'}</dd></div><div><dt>모델</dt><dd>{run.model??model}</dd></div><div><dt>입력 토큰</dt><dd>{run.tokensEstimated?'약 ':''}{run.inputTokens??'-'}</dd></div><div><dt>출력 토큰</dt><dd>{run.tokensEstimated?'약 ':''}{run.outputTokens??'-'}</dd></div><div><dt>소요 시간</dt><dd>{run.durationMs===undefined?'-':`${(run.durationMs/1000).toFixed(1)}초`}</dd></div><div><dt>생성 시각</dt><dd>{new Date(run.createdAt).toLocaleString()}</dd></div>{#if run.finishReason}<div><dt>종료 이유</dt><dd>{run.finishReason}</dd></div>{/if}{#if run.generationId}<div><dt>생성 ID</dt><dd>{run.generationId}</dd></div>{/if}</dl><details><summary>이 응답에 사용한 프롬프트</summary>{#if run.prompt}<pre>{run.prompt.messages.map(item=>`[${item.role}]\n${item.content}`).join('\n\n')}</pre>{:else}<p>오래된 실행은 감사용 해시만 보존합니다. {run.promptHash??''}</p>{/if}</details></section>{/if}{/if}
        {#if message.role==='assistant'&&(factsFor(message,index).length||message.chips?.length||(index===messages.length-1&&narrativeWarning))}<div class="chips">{#each factsFor(message,index) as fact}<span class:rejected={fact.rejected}><Icon name={fact.rejected?'blocked':'star'} size={12}/><i>{fact.label}</i><b>{fact.delta??fact.note??''}</b></span>{/each}{#each message.chips??[] as chip}<span class:rejected={!chip.ok}><Icon name={chip.ok?'star':'blocked'} size={12}/><i>{chip.text}</i></span>{/each}{#if index===messages.length-1&&narrativeWarning}<button class="issue-chip" class:strong={narrativeWarning.strong} aria-expanded={issuesOpen} onclick={()=>issuesOpen=!issuesOpen}><Icon name="alert" size={12}/>{narrativeWarning.label}</button>{/if}</div>{#if index===messages.length-1&&narrativeWarning&&issuesOpen}<section class="issue-detail" class:strong={narrativeWarning.strong} aria-label="서사 검증 경고"><ul>{#each narrativeWarning.details as detail}<li>{detail}</li>{/each}</ul></section>{/if}{/if}
      </div>
    </article>
  {/each}
  {#if waiting}<article class="message typing" aria-label="응답 작성 중"><div class="avatar">{cardName.slice(0,1)}</div><div class="thinking"><div class="dots"><i></i><i></i><i></i></div><span>응답을 만들고 있습니다…</span></div></article>{/if}
  <div class="chat-bottom" data-chat-bottom bind:this={bottom} aria-hidden="true"></div>
</div>

<style>
  .list{padding:26px 20px 120px}.message{display:grid;grid-template-columns:56px minmax(0,1fr);gap:16px;margin:0 auto 22px;max-width:900px}.avatar{width:56px;height:56px;border-radius:6px;background:#292d36;display:grid;place-items:center;font:700 20px sans-serif;overflow:hidden;box-shadow:0 2px 8px #0006}.avatar.empty{background:#1b1e25;box-shadow:inset 0 0 0 1px #2c313b}.avatar img{width:100%;height:100%;object-fit:cover}.head{display:flex;align-items:center;gap:8px;min-height:27px}.head strong{font-size:18px}.tools{margin-left:auto;display:flex;position:relative}.tools button,.swipe button{display:grid;place-items:center;border:0;background:transparent;color:#858b98;padding:4px;transition:.12s}.tools button:hover,.swipe button:hover{color:#78a2ff}.tools button:active,.swipe button:active{transform:scale(.9)}button:focus-visible{outline:2px solid #6c98f4;outline-offset:2px}.menu{position:absolute;right:0;top:100%;z-index:5;min-width:210px;padding:4px;border:1px solid #3a4150;border-radius:7px;background:#1c2029}.menu button{width:100%;padding:8px;color:#ddd}.text{color:#e7e0d4;font:15.5px/1.65 Georgia,'Noto Serif KR',serif}.user .text{font-family:system-ui,sans-serif;color:#d9dde7}.text :global(p){margin:2px 0 10px}.text :global(.dialogue){color:#e5bf79}.text :global(pre){overflow:auto;padding:12px;border-radius:7px;background:#0d0f13}.text :global(code){font:13px ui-monospace;background:#252932;padding:1px 4px;border-radius:3px}.text :global(blockquote){margin:8px 0;padding-left:12px;border-left:3px solid #6d7890;color:#b8bdc7}.text :global(a){color:#8fb3ff}.text :global(img){max-width:100%;height:auto;border-radius:8px}.text :global(.illust){max-width:560px;margin:8px 0;border:1px solid #353942;border-radius:8px;overflow:hidden}.text :global(.illust img){display:block;width:100%;height:auto}.text :global(figcaption){padding:6px 10px;font:11px ui-monospace;color:#8d94a2}.body textarea{width:100%;min-height:110px;padding:10px;background:#191c22;color:#eee;border:1px solid #6793ef}.editor>div{display:flex;justify-content:flex-end;gap:6px;margin-top:6px}.editor button{padding:5px 11px;border:1px solid #414754;border-radius:5px;background:#222630;color:#ddd}.meta{display:flex;justify-content:flex-end;align-items:center;gap:12px;margin-top:5px;font:11px sans-serif;color:#727887}.model,.swipe{display:flex;align-items:center;gap:5px}.model{padding:3px 7px;border-radius:8px}.chips{display:flex;gap:6px;flex-wrap:wrap;margin-top:8px}.chips span{display:flex;align-items:center;gap:5px;border:1px solid #3b4149;border-left:2px solid #d8b36a;border-radius:5px;padding:3px 8px;font:11px ui-monospace;color:#dce0e6}.chips i{font-style:normal;color:#9299a7}.chips .rejected{border-left-color:#d06d55;color:#e0a7b0}.issue-chip{display:flex;align-items:center;gap:5px;border:1px solid #8d713c;border-left:2px solid #d8b36a;border-radius:5px;padding:3px 8px;background:#2c281f;color:#e3c78f;font:11px ui-monospace;cursor:pointer}.issue-chip.strong{border-color:#9c5048;background:#351f22;color:#f0aaa3}.issue-detail{margin-top:7px;padding:9px 11px;border:1px solid #806634;border-radius:6px;background:#242119;color:#d9c8a7;font:12px/1.5 sans-serif}.issue-detail.strong{border-color:#9c5048;background:#2e1d20;color:#efb3ad}.issue-detail ul{margin:0 0 8px;padding-left:18px}.typing{align-items:center}.dots{display:flex;gap:5px;padding:20px 4px}.dots i{width:7px;height:7px;border-radius:50%;background:#8e96a6;animation:pulse 1s infinite}.dots i:nth-child(2){animation-delay:.15s}.dots i:nth-child(3){animation-delay:.3s}@keyframes pulse{50%{opacity:.25;transform:translateY(-3px)}}@media(prefers-reduced-motion:reduce){.dots i{animation:none}}@media(max-width:680px){.list{padding-inline:10px}.message{grid-template-columns:42px 1fr;gap:10px}.avatar{width:42px;height:42px}}
  .text :global(img){max-width:min(100%,var(--asset-width,32rem))}.text :global(.illust){max-width:min(100%,var(--asset-width,32rem))}.translation{margin-top:10px;padding:10px 12px;border-left:2px solid #6c98f4;background:#171b23}.translation>small{display:block;margin-bottom:6px;color:#8fb3ff;font:10px ui-monospace}.tokens{font:10px ui-monospace;color:#8b93a2}.run-detail{margin-top:7px;padding:10px;border:1px solid #39404d;border-radius:7px;background:#171a20;color:#cfd4de;font:12px sans-serif}.run-detail header{display:flex;justify-content:space-between;align-items:center}.run-detail header button{border:0;background:transparent;color:#9299a7}.run-detail dl{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:5px 14px}.run-detail dl div{display:flex;justify-content:space-between;gap:12px}.run-detail dt{color:#818a99}.run-detail dd{margin:0;text-align:right;overflow-wrap:anywhere}.run-detail details{margin-top:8px}.run-detail pre{max-height:280px;overflow:auto;white-space:pre-wrap;background:#0e1014;padding:10px;border-radius:5px;font:11px/1.45 ui-monospace}
  .response-sprites{display:grid;max-width:min(100%,var(--asset-width,32rem));margin:6px 0 12px}.response-sprites.multiple{grid-template-columns:repeat(auto-fit,minmax(min(12rem,100%),1fr));gap:8px;max-width:100%}.response-sprites figure{display:grid;align-items:end;min-width:0;margin:0;border-radius:8px;overflow:hidden;background:transparent}.response-sprites img{display:block;width:100%;max-height:min(58vh,36rem);object-fit:contain;object-position:center bottom}.thinking{display:flex;align-items:center;gap:8px;color:#9299a7;font:12px system-ui}.chat-bottom{height:1px;scroll-margin-bottom:12px}
  .tools{align-items:center;gap:2px}.tools .tool-label{padding-inline:6px;font:11px system-ui}.tools .active{color:#a8c2ff;background:#252b36}.tools .swipe{gap:1px;padding:0 2px;border-radius:6px;background:#1b1f27}.tools .swipe b{min-width:34px;text-align:center;color:#8d95a4;font:10px ui-monospace}.tools button:disabled{opacity:.35}.menu button{display:flex;align-items:center;justify-content:flex-start;gap:7px;min-height:34px;text-align:left}.meta{gap:8px}.issue-detail{padding-bottom:9px}@media(max-width:680px){.head{align-items:flex-start}.head strong{font-size:16px}.tools{flex-wrap:wrap;justify-content:flex-end}.tools>button,.tools .swipe button{min-width:32px;min-height:32px}.tools .tool-label{min-width:auto}.menu{top:34px}.meta{margin-top:2px}.response-sprites img{max-height:28rem}}
</style>
